import android.util.Log
import timber.log.Timber

class LoggingTree : Timber.Tree() {
    override fun log(priority: Int, tag: String?, message: String, t: Throwable?) {
        when (priority) {
            Log.VERBOSE -> println("V/$tag: $message")
            Log.DEBUG -> println("D/$tag: $message")
            Log.INFO -> println("I/$tag: $message")
            Log.WARN -> println("W/$tag: $message")
            Log.ERROR -> println("E/$tag: $message")
            Log.ASSERT -> println("A/$tag: $message")
        }
    }
}

class AppLogger {
    companion object {
        fun initialize() {
            if (BuildConfig.DEBUG) {
                Timber.plant(Timber.DebugTree())
            } else {
                Timber.plant(LoggingTree())
            }
        }

        fun logUserAuthentication(success: Boolean, username: String) {
            val status = if (success) "Success" else "Failed"
            Timber.i("Auth attempt for $username - $status")
        }

        fun logDatabaseQuery(query: String, parameters: Map<String, Any>) {
            Timber.v("DB Query: $query with params: $parameters")
        }

        fun logApiRequest(method: String, url: String, headers: Map<String, String>, body: String) {
            Timber.d("API Request - Method: $method, URL: $url, Headers: $headers, Body: $body")
        }
    }
}

